const originalTextNodes = new WeakMap();
const originalAttributes = new WeakMap();

const byId = (id) => document.getElementById(id);
const all = (selector, root = document) => [...root.querySelectorAll(selector)];

let state = loadState();
let currentLanguage = loadLanguage();
let currentDocumentFolder = [];
let deferredInstallPrompt = null;
let serviceWorkerRegistration = null;
let updateRegistration = null;
let reloadForUpdate = false;
let updateInProgress = false;
let updateCheckTimer = null;

function loadLanguage() {
  try {
    const saved = localStorage.getItem(LANGUAGE_KEY);
    if (saved === "de" || saved === "en") return saved;
  } catch {}
  return navigator.language?.toLowerCase().startsWith("de") ? "de" : "en";
}

function translateValue(value, language = currentLanguage) {
  const source = String(value ?? "");
  if (language !== "de") return source;
  const normalized = source.replace(/\s+/g, " ").trim();
  if (DE_TRANSLATIONS[normalized]) return DE_TRANSLATIONS[normalized];

  let match = normalized.match(/^(\d+) (element|elements)$/);
  if (match) return `${match[1]} ${Number(match[1]) === 1 ? "Element" : "Elemente"}`;
  match = normalized.match(/^(\d+) (connector|connectors)$/);
  if (match) return `${match[1]} Steckverbinder`;
  match = normalized.match(/^(\d+) (group|groups)$/);
  if (match) return `${match[1]} ${Number(match[1]) === 1 ? "Gruppe" : "Gruppen"}`;
  match = normalized.match(/^(\d+) (document|documents)$/);
  if (match) return `${match[1]} ${Number(match[1]) === 1 ? "Dokument" : "Dokumente"}`;
  match = normalized.match(/^Supports (.+)$/);
  if (match) return `Unterstützt ${match[1]}`;
  match = normalized.match(/^Select a module for AU(\d+)\.$/);
  if (match) return `Modul für AU${match[1]} auswählen.`;
  match = normalized.match(/^No additional position-specific setting is stored for AU(\d+)\.$/);
  if (match) return `Für AU${match[1]} ist keine zusätzliche positionsspezifische Einstellung hinterlegt.`;
  match = normalized.match(/^eSBl carton (.+)$/);
  if (match) return `eSBl-Karton ${match[1]}`;
  match = normalized.match(/^cSBl carton (.+)$/);
  if (match) return `cSBl-Karton ${match[1]}`;
  match = normalized.match(/^Spacer for SB when E801 modules are consecutive(.*)$/);
  if (match) return `Abstandshalter für SB bei direkt aufeinanderfolgenden E801-Modulen${match[1]}`;
  match = normalized.match(/^Version (.+)$/);
  if (match) return `Version ${match[1]}`;
  match = normalized.match(/^Build (.+)$/);
  if (match) return `Stand ${match[1]}`;
  return source;
}

function translateTextNode(node) {
  if (!originalTextNodes.has(node)) originalTextNodes.set(node, node.nodeValue);
  const original = originalTextNodes.get(node);
  const match = original.match(/^(\s*)([\s\S]*?)(\s*)$/);
  const translated = translateValue(match[2]);
  node.nodeValue = `${match[1]}${translated}${match[3]}`;
}

function translateAttributes(element) {
  const attributes = ["aria-label", "placeholder", "alt", "title"];
  let originals = originalAttributes.get(element);
  if (!originals) {
    originals = new Map();
    originalAttributes.set(element, originals);
  }
  attributes.forEach((attribute) => {
    if (!element.hasAttribute(attribute)) return;
    if (!originals.has(attribute)) originals.set(attribute, element.getAttribute(attribute));
    element.setAttribute(attribute, translateValue(originals.get(attribute)));
  });
}

function setTranslatableAttribute(element, attribute, englishValue) {
  if (!element) return;
  let originals = originalAttributes.get(element);
  if (!originals) {
    originals = new Map();
    originalAttributes.set(element, originals);
  }
  originals.set(attribute, englishValue);
  element.setAttribute(attribute, translateValue(englishValue));
}

function translateSubtree(root = document.body) {
  if (!root) return;
  if (root.nodeType === Node.TEXT_NODE) translateTextNode(root);
  const walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT);
  let node = walker.nextNode();
  while (node) {
    if (!node.parentElement?.closest("script, style")) translateTextNode(node);
    node = walker.nextNode();
  }
  if (root instanceof Element) translateAttributes(root);
  all("[aria-label], [placeholder], [alt], [title]", root).forEach(translateAttributes);
}

function applyLanguageToDocument() {
  document.documentElement.lang = currentLanguage;
  all("[data-language]").forEach((button) => {
    const active = button.dataset.language === currentLanguage;
    button.classList.toggle("is-active", active);
    button.setAttribute("aria-pressed", String(active));
  });
  translateSubtree(document.body);
  const route = ROUTES.has(location.hash.slice(1)) ? location.hash.slice(1) : "configure";
  const routeTitles = {
    configure: "Configuration",
    connectors: "Disconnect connectors",
    assembly: "Additional assembly",
    documents: "Documents",
    contact: "Contact",
  };
  document.title = `${translateValue(routeTitles[route])} · ${APP_META.name}`;
  document.querySelector('meta[name="description"]')?.setAttribute(
    "content",
    currentLanguage === "de"
      ? "PCC Prep Assist unterstützt bei Konfiguration, Schalterstellungen, Steckverbindern und Montage für cobas pro und cobas pure."
      : "PCC Prep Assist provides configuration, switch, connector and assembly guidance for cobas pro and cobas pure preparations.",
  );
}

function setLanguage(language, { notify = true } = {}) {
  if (language !== "de" && language !== "en") return;
  currentLanguage = language;
  try {
    localStorage.setItem(LANGUAGE_KEY, language);
  } catch {}
  renderDocuments();
  renderAll({ animate: false });
  setRoute(location.hash.slice(1), { updateHash: false });
  applyLanguageToDocument();
  if (notify) {
    showToast(
      "Language changed",
      language === "de"
        ? "The interface is now displayed in German."
        : "The interface is now displayed in English.",
      "success",
    );
  }
}

function initLanguage() {
  all("[data-language]").forEach((button) => {
    button.addEventListener("click", () => setLanguage(button.dataset.language));
  });
  applyLanguageToDocument();
}

function loadState() {
  try {
    return sanitizeState(JSON.parse(localStorage.getItem(STORAGE_KEY)));
  } catch {
    return createDefaultState();
  }
}

function saveState() {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  } catch {
    // Storage can be unavailable in private browsing. The app still remains usable.
  }
}

function escapeHtml(value) {
  return String(value)
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;")
    .replaceAll("'", "&#039;");
}

function formatBuildDate(value) {
  const [year, month, day] = value.split("-");
  return `${day}.${month}.${year}`;
}

function setText(id, value) {
  const element = byId(id);
  if (element) element.textContent = value;
}

function icon(name, size = 20) {
  const paths = {
    check: '<path d="m5 12 4 4L19 6"/>',
    alert:
      '<path d="M12 9v4m0 4h.01M10.3 3.4 2.6 16.7A2 2 0 0 0 4.3 20h15.4a2 2 0 0 0 1.7-3.3L13.7 3.4a2 2 0 0 0-3.4 0Z"/>',
    info: '<circle cx="12" cy="12" r="9"/><path d="M12 11v5m0-8h.01"/>',
    copy: '<rect x="8" y="8" width="11" height="11" rx="2"/><path d="M16 8V5a2 2 0 0 0-2-2H5a2 2 0 0 0-2 2v9a2 2 0 0 0 2 2h3"/>',
    reset: '<path d="M3 12a9 9 0 1 0 3-6.7L3 8"/><path d="M3 3v5h5"/>',
    arrow: '<path d="m9 18 6-6-6-6"/>',
    download: '<path d="M12 3v12m0 0 4-4m-4 4-4-4"/><path d="M4 19h16"/>',
    external:
      '<path d="M14 3h7v7m0-7-9 9"/><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"/>',
    close: '<path d="m6 6 12 12M18 6 6 18"/>',
    search: '<circle cx="11" cy="11" r="7"/><path d="m20 20-4-4"/>',
    folder: '<path d="M3 6.5A2.5 2.5 0 0 1 5.5 4H10l2 2h6.5A2.5 2.5 0 0 1 21 8.5v8A2.5 2.5 0 0 1 18.5 19h-13A2.5 2.5 0 0 1 3 16.5Z"/>',
    home: '<path d="m3 11 9-8 9 8"/><path d="M5 10v10h14V10M9 20v-6h6v6"/>',
    sun: '<circle cx="12" cy="12" r="4"/><path d="M12 2v2m0 16v2M4.9 4.9l1.4 1.4m11.4 11.4 1.4 1.4M2 12h2m16 0h2M4.9 19.1l1.4-1.4M17.7 6.3l1.4-1.4"/>',
    moon: '<path d="M20 15.2A8.5 8.5 0 0 1 8.8 4 8.5 8.5 0 1 0 20 15.2Z"/>',
  };
  return `<svg aria-hidden="true" width="${size}" height="${size}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round">${paths[name] || paths.info}</svg>`;
}

async function copyText(value) {
  if (navigator.clipboard?.writeText) {
    try {
      await navigator.clipboard.writeText(value);
      return true;
    } catch {
      // Fall through to the legacy copy path.
    }
  }

  try {
    const area = document.createElement("textarea");
    area.value = value;
    area.setAttribute("readonly", "");
    area.style.position = "fixed";
    area.style.opacity = "0";
    document.body.appendChild(area);
    area.select();
    const copied = document.execCommand("copy");
    area.remove();
    return copied;
  } catch {
    return false;
  }
}

function showToast(title, message = "", tone = "default") {
  const stack = byId("toastStack");
  if (!stack) return;

  const toast = document.createElement("div");
  toast.className = `toast toast--${tone}`;
  toast.setAttribute("role", "status");
  toast.innerHTML = `
    <span class="toast__icon">${icon(tone === "success" ? "check" : tone === "warning" ? "alert" : "info", 18)}</span>
    <span><strong>${escapeHtml(title)}</strong>${message ? `<small>${escapeHtml(message)}</small>` : ""}</span>
  `;
  stack.appendChild(toast);
  translateSubtree(toast);
  requestAnimationFrame(() => toast.classList.add("is-visible"));
  window.setTimeout(() => {
    toast.classList.remove("is-visible");
    window.setTimeout(() => toast.remove(), 300);
  }, 3200);
}

function applyTheme(theme) {
  const resolved =
    theme === "dark" || theme === "light"
      ? theme
      : window.matchMedia("(prefers-color-scheme: dark)").matches
        ? "dark"
        : "light";
  document.documentElement.dataset.theme = resolved;
  setTranslatableAttribute(
    byId("themeToggle"),
    "aria-label",
    `Switch to ${resolved === "dark" ? "light" : "dark"} mode`,
  );
  byId("themeIcon") &&
    (byId("themeIcon").innerHTML = icon(
      resolved === "dark" ? "sun" : "moon",
      19,
    ));
  document
    .querySelector('meta[name="theme-color"]')
    ?.setAttribute("content", resolved === "dark" ? "#07111f" : "#f5f8fc");
}

function initTheme() {
  let saved = "auto";
  try {
    saved = localStorage.getItem(THEME_KEY) || "auto";
  } catch {}
  applyTheme(saved);

  byId("themeToggle")?.addEventListener("click", () => {
    const next =
      document.documentElement.dataset.theme === "dark" ? "light" : "dark";
    try {
      localStorage.setItem(THEME_KEY, next);
    } catch {}
    applyTheme(next);
  });
}

function setRoute(route, { updateHash = true } = {}) {
  const safeRoute = ROUTES.has(route) ? route : "configure";
  const labels = {
    configure: [
      "Configuration",
      "Build the system and verify switch settings.",
    ],
    connectors: [
      "Disconnect connectors",
      "Connector guidance derived from the current configuration.",
    ],
    assembly: [
      "Additional assembly",
      "Accessories and final-build items for the selected modules.",
    ],
    documents: ["Documents", "Reference documents for preparation and adjustment."],
    contact: ["Contact", "PCC Monsheim contact information."],
  };

  all("[data-page]").forEach((page) => {
    const active = page.dataset.page === safeRoute;
    page.hidden = !active;
    page.classList.toggle("is-active", active);
  });

  all("[data-route]").forEach((link) => {
    const active = link.dataset.route === safeRoute;
    link.classList.toggle("is-active", active);
    if (active) link.setAttribute("aria-current", "page");
    else link.removeAttribute("aria-current");
  });

  setText("pageTitle", labels[safeRoute][0]);
  setText("pageSubtitle", labels[safeRoute][1]);
  document.title = `${translateValue(labels[safeRoute][0])} · ${APP_META.name}`;
  if (updateHash) history.replaceState(null, "", `#${safeRoute}`);
  applyLanguageToDocument();
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function initNavigation() {
  all("[data-route]").forEach((link) => {
    link.addEventListener("click", (event) => {
      event.preventDefault();
      setRoute(link.dataset.route);
    });
  });

  window.addEventListener("hashchange", () =>
    setRoute(location.hash.slice(1), { updateHash: false }),
  );
  setRoute(location.hash.slice(1), { updateHash: false });
}

function createFactRows(rows) {
  if (!rows.length) return "";
  return rows
    .map(
      ([label, value, tone]) => `
      <div class="fact-row">
        <span>${escapeHtml(label)}</span>
        <strong class="fact-value${tone ? ` fact-value--${tone}` : ""}">${escapeHtml(value)}</strong>
      </div>
    `,
    )
    .join("");
}

function renderMode() {
  const isPro = state.mode === "pro";
  byId("proConfig").hidden = !isPro;
  byId("pureConfig").hidden = isPro;
  byId("proModeButton").classList.toggle("is-active", isPro);
  byId("pureModeButton").classList.toggle("is-active", !isPro);
  byId("proModeButton").setAttribute("aria-selected", String(isPro));
  byId("pureModeButton").setAttribute("aria-selected", String(!isPro));
  byId("modeIndicator").classList.toggle("is-pure", !isPro);
  setText("currentSystemLabel", isPro ? "cobas pro" : "cobas pure");
}

function renderProInputs() {
  const iseGuidance = getProIseGuidance(state.pro);
  byId("iseType").value = iseGuidance.type;
  setText("iseState", iseGuidance.type || "Not included");
  setText(
    "ssuSwitchValue",
    iseGuidance.ssuSw14 || "No change documented",
  );
  byId("iseCard").classList.toggle("is-selected", Boolean(iseGuidance.type));
  byId("iseSwitchInfo").innerHTML = iseGuidance.moduleFacts.length
    ? `<div class="fact-group"><span class="fact-group__title">ISE exhibition mode</span>${createFactRows(iseGuidance.moduleFacts)}</div>`
    : `<p class="inline-note">${escapeHtml(
        iseGuidance.type === "ISE NEO"
          ? "No additional ISE switch setting is required."
          : "No ISE module selected",
      )}</p>`;

  const validation = validatePro(state.pro);
  for (let position = 1; position <= 4; position += 1) {
    const select = byId(`au${position}`);
    select.value = state.pro.aus[position - 1];
    const card = byId(`auCard${position}`);
    const code = state.pro.aus[position - 1];
    card.classList.toggle("is-selected", Boolean(code));
    card.classList.toggle(
      "is-invalid",
      validation.invalidPositions.includes(position),
    );
    card.classList.toggle(
      "is-warning",
      validation.warningPositions.includes(position),
    );
    card.dataset.module = code || "empty";

    const info = getModuleInfo(code, position);
    const infoElement = byId(`auInfo${position}`);
    if (!info) {
      infoElement.innerHTML = `
        <div class="empty-state empty-state--compact">
          <span class="empty-state__dot"></span>
          <span>Select a module for AU${position}.</span>
        </div>`;
      continue;
    }

    infoElement.innerHTML = `
      <div class="switch-summary">
        <div class="switch-summary__head">
          <span class="module-chip module-chip--${info.accent}">${escapeHtml(code)}</span>
          <span>AU${position}</span>
        </div>
        <div class="fact-group">
          <span class="fact-group__title">SB rotary switch</span>
          ${createFactRows([["SW16", SB_SWITCH_BY_AU[position]]])}
        </div>
        ${
          iseGuidance.sbFacts.length
            ? `<div class="fact-group">
                <span class="fact-group__title">SB exhibition mode</span>
                ${createFactRows(iseGuidance.sbFacts)}
              </div>`
            : ""
        }
        <div class="fact-group">
          <span class="fact-group__title">Exhibition mode</span>
          ${createFactRows(info.exhibition)}
        </div>
        ${
          info.position.length
            ? `
          <div class="fact-group">
            <span class="fact-group__title">Position-specific setting</span>
            ${createFactRows(info.position)}
          </div>`
            : `
          <p class="inline-note">No additional position-specific setting is stored for AU${position}.</p>`
        }
      </div>`;
  }
}

function renderPureInputs() {
  byId("pureE402").checked = state.pure.e402;
  byId("pureC303").checked = state.pure.c303;
  byId("pureE402Card").classList.toggle("is-selected", state.pure.e402);
  byId("pureC303Card").classList.toggle("is-selected", state.pure.c303);

  const info = getPureSwitchInfo(state.pure);
  const rows = [
    ["pureE402Info", info.e402, "E402 is not included."],
    ["pureSSUInfo", info.ssu, ""],
    ["pureC303Info", info.c303, "C303 is not included."],
  ];
  rows.forEach(([id, facts, empty]) => {
    byId(id).innerHTML = facts.length
      ? `<div class="fact-group">${createFactRows(facts)}</div>`
      : `<p class="inline-note">${escapeHtml(empty)}</p>`;
  });
}

function renderValidation() {
  const banner = byId("validationBanner");
  const iconElement = byId("validationIcon");
  const title = byId("validationTitle");
  const message = byId("validationMessage");
  const detailList = byId("validationDetails");

  if (state.mode === "pure") {
    banner.dataset.status = "valid";
    iconElement.innerHTML = icon("check", 22);
    title.textContent = "Pure configuration ready";
    message.textContent =
      "Switch guidance is available for the selected modules.";
    detailList.innerHTML = "";
    return;
  }

  const result = validatePro(state.pro);
  banner.dataset.status = result.status;
  iconElement.innerHTML = icon(
    result.status === "error" || result.status === "warning"
      ? "alert"
      : result.status === "empty"
        ? "info"
        : "check",
    22,
  );
  title.textContent = {
    empty: "Start your configuration",
    valid: "Configuration check passed",
    warning: "Configuration needs verification",
    error: "Configuration conflict",
  }[result.status];
  message.textContent = result.message;
  detailList.innerHTML = [...result.errors, ...result.warnings]
    .slice(1)
    .map((item) => `<li>${escapeHtml(item)}</li>`)
    .join("");
}

function renderSequence() {
  const sequence =
    state.mode === "pro"
      ? buildSequencePro(state.pro)
      : buildSequencePure(state.pure);
  const rail = byId("sequenceRail");
  rail.innerHTML = sequence
    .map(
      (item, index) => `
      <div class="rail-item" style="--item-index:${index}" data-kind="${escapeHtml(item.type.toLowerCase())}">
        <span class="rail-item__index">${String(index + 1).padStart(2, "0")}</span>
        <span class="rail-item__body">
          <strong>${escapeHtml(item.code)}</strong>
          <small>${escapeHtml(item.label)}</small>
        </span>
      </div>
    `,
    )
    .join("");

  setText(
    "sequenceCount",
    `${sequence.length} ${sequence.length === 1 ? "element" : "elements"}`,
  );
  setText(
    "metricModules",
    String(sequence.filter((item) => item.type === "Module").length),
  );
}

function renderConnectors() {
  const grid = byId("connectorGrid");
  const empty = byId("connectorEmpty");
  const note = byId("connectorModeNote");

  if (state.mode === "pure") {
    grid.innerHTML = "";
    empty.hidden = false;
    note.textContent = "cobas pure";
    setText("connectorCount", "0 connectors");
    setText("metricConnectors", "0");
    return;
  }

  const groups = getProConnectorGroups(state.pro);
  empty.hidden = groups.length > 0;
  note.textContent = "cobas pro";
  grid.innerHTML = groups
    .map(
      (group, index) => `
      <article class="connector-card" style="--item-index:${index}">
        <div class="connector-card__head">
          <span class="connector-card__number">${String(index + 1).padStart(2, "0")}</span>
          <span><strong>${escapeHtml(group.title)}</strong><small>${escapeHtml(group.subtitle)}</small></span>
        </div>
        <div class="connector-tags">
          ${group.connectors.map((connector) => `<span>${escapeHtml(connector)}</span>`).join("")}
        </div>
      </article>
    `,
    )
    .join("");

  const count = groups.reduce((sum, group) => sum + group.connectors.length, 0);
  setText(
    "connectorCount",
    `${count} ${count === 1 ? "connector" : "connectors"}`,
  );
  setText("metricConnectors", String(count));
}

function renderAssembly() {
  const groups = state.mode === "pro" ? getProAssemblyGroups(state.pro) : [];
  const list = byId("assemblyList");
  const empty = byId("assemblyEmpty");

  empty.hidden = groups.length > 0;
  list.innerHTML = groups
    .map(
      (group, index) => `
      <details class="assembly-card" style="--item-index:${index}" ${index < 2 ? "open" : ""}>
        <summary>
          <span class="assembly-card__number">${String(index + 1).padStart(2, "0")}</span>
          <span class="assembly-card__title"><strong>${escapeHtml(group.title)}</strong><small>${escapeHtml(group.category)}</small></span>
          <span class="assembly-card__count">${group.items.length}</span>
          <span class="assembly-card__chevron">${icon("arrow", 18)}</span>
        </summary>
        <ul>${group.items.map((item) => `<li>${escapeHtml(item)}</li>`).join("")}</ul>
      </details>
    `,
    )
    .join("");

  const itemCount = groups.reduce((sum, group) => sum + group.items.length, 0);
  setText(
    "assemblyCount",
    `${groups.length} ${groups.length === 1 ? "group" : "groups"}`,
  );
  setText("metricTasks", String(itemCount));
}

function localizedDocumentValue(document, field) {
  if (currentLanguage === "de") return document[`${field}De`] || document[field] || "";
  return document[field] || "";
}

function documentFolderLabel(segment) {
  const meta = DOCUMENT_FOLDER_META[segment];
  if (!meta) return segment;
  return currentLanguage === "de" ? meta.labelDe : meta.label;
}

function documentFolderStartsWith(folder, prefix) {
  return prefix.every((segment, index) => folder[index] === segment);
}

function renderDocumentBreadcrumb() {
  const breadcrumb = byId("documentBreadcrumb");
  const crumbs = [
    { depth: 0, label: translateValue("Documents"), home: true },
    ...currentDocumentFolder.map((segment, index) => ({
      depth: index + 1,
      label: documentFolderLabel(segment),
    })),
  ];
  breadcrumb.innerHTML = crumbs
    .map(
      (crumb, index) => `
        ${index ? '<span class="document-breadcrumb__separator" aria-hidden="true">›</span>' : ""}
        <button type="button" data-document-folder-depth="${crumb.depth}"${crumb.depth === currentDocumentFolder.length ? ' aria-current="page"' : ""}>
          ${crumb.home ? icon("home", 14) : ""}${escapeHtml(crumb.label)}
        </button>`,
    )
    .join("");
  all("[data-document-folder-depth]", breadcrumb).forEach((button) => {
    button.addEventListener("click", () => {
      currentDocumentFolder = currentDocumentFolder.slice(
        0,
        Number(button.dataset.documentFolderDepth),
      );
      renderDocuments();
    });
  });
}

function renderDocuments() {
  const grid = byId("documentGrid");
  const folderGrid = byId("documentFolderGrid");
  const query = byId("documentSearchInput")?.value.trim().toLowerCase() || "";
  const system = byId("documentSystemFilter")?.value || "";
  const category = byId("documentCategoryFilter")?.value || "";
  const hasActiveFilter = Boolean(query || system || category);
  const scopedDocuments = DOCUMENTS.filter((document) =>
    documentFolderStartsWith(document.folder, currentDocumentFolder),
  );
  const matchedDocuments = scopedDocuments.filter((document) => {
    if (system && document.system !== system) return false;
    if (category && document.category !== category) return false;
    const haystack = [
      document.title,
      document.titleDe,
      document.description,
      document.descriptionDe,
      document.system,
      document.category,
      document.categoryDe,
      document.type,
      ...document.folder.map(documentFolderLabel),
    ]
      .filter(Boolean)
      .join(" ")
      .toLowerCase();
    return !query || haystack.includes(query);
  });
  const visibleDocuments = hasActiveFilter
    ? matchedDocuments
    : matchedDocuments.filter(
        (document) => document.folder.length === currentDocumentFolder.length,
      );
  const childFolders = hasActiveFilter
    ? []
    : [
        ...new Set(
          scopedDocuments
            .filter(
              (document) =>
                document.folder.length > currentDocumentFolder.length,
            )
            .map((document) => document.folder[currentDocumentFolder.length]),
        ),
      ];

  renderDocumentBreadcrumb();
  folderGrid.hidden = childFolders.length === 0;
  folderGrid.innerHTML = childFolders
    .map((segment, index) => {
      const path = [...currentDocumentFolder, segment];
      const count = scopedDocuments.filter((document) =>
        documentFolderStartsWith(document.folder, path),
      ).length;
      const label = documentFolderLabel(segment);
      return `
        <button class="document-folder-card" type="button" data-document-folder="${escapeHtml(segment)}" aria-label="${escapeHtml(`${translateValue("Open folder")}: ${label}`)}" style="--item-index:${index}">
          <span class="document-folder-card__icon">${icon("folder", 23)}</span>
          <span class="document-folder-card__body"><strong>${escapeHtml(label)}</strong><small>${escapeHtml(translateValue(`${count} ${count === 1 ? "document" : "documents"}`))}</small></span>
          <span class="document-folder-card__arrow">${icon("arrow", 17)}</span>
        </button>`;
    })
    .join("");
  all("[data-document-folder]", folderGrid).forEach((button) => {
    button.addEventListener("click", () => {
      currentDocumentFolder = [
        ...currentDocumentFolder,
        button.dataset.documentFolder,
      ];
      renderDocuments();
      byId("documentBreadcrumb")?.scrollIntoView({
        behavior: "smooth",
        block: "nearest",
      });
    });
  });

  setText(
    "documentResultCount",
    translateValue(
      `${matchedDocuments.length} ${matchedDocuments.length === 1 ? "document" : "documents"}`,
    ),
  );
  byId("documentEmpty").hidden =
    visibleDocuments.length > 0 || childFolders.length > 0;
  grid.hidden = visibleDocuments.length === 0;
  grid.innerHTML = visibleDocuments
    .map((document, index) => {
      const title = localizedDocumentValue(document, "title");
      const description = localizedDocumentValue(document, "description");
      const categoryLabel = localizedDocumentValue(document, "category");
      const action = document.external
        ? "Open RDK procedure"
        : document.type === "PPTX"
          ? "Download presentation"
          : "Open document";
      return `
      <article class="document-card" id="document-${escapeHtml(document.id)}" data-document-type="${escapeHtml(document.type)}" style="--item-index:${Math.min(index, 8)}">
        <div class="document-card__visual"><span>${escapeHtml(document.type)}</span></div>
        <div class="document-card__body">
          <div class="document-card__meta"><span>${escapeHtml(translateValue(document.system))}</span><span>${escapeHtml(categoryLabel)}</span><span>${escapeHtml(document.size)}</span></div>
          <h3>${escapeHtml(title)}</h3>
          <p>${escapeHtml(description)}</p>
          <a class="button button--secondary" href="${escapeHtml(document.href)}" target="_blank" rel="noopener"${document.type === "PPTX" ? " download" : ""}>
            ${icon("external", 18)} ${translateValue(action)}
          </a>
        </div>
      </article>`;
    })
    .join("");
}

function initDocuments() {
  byId("documentSearchInput")?.addEventListener("input", renderDocuments);
  byId("documentSystemFilter")?.addEventListener("change", renderDocuments);
  byId("documentCategoryFilter")?.addEventListener("change", renderDocuments);
}

function renderMetrics() {
  const selected =
    state.mode === "pro"
      ? state.pro.aus.filter(Boolean).length + (state.pro.iseType ? 1 : 0) + 1
      : (state.pure.e402 ? 1 : 0) + (state.pure.c303 ? 1 : 0) + 1;
  setText("metricSelected", String(selected));
}

function renderAll({ animate = true } = {}) {
  renderMode();
  renderProInputs();
  renderPureInputs();
  renderValidation();
  renderSequence();
  renderConnectors();
  renderAssembly();
  renderMetrics();
  saveState();
  applyLanguageToDocument();

  if (animate) {
    const workspace = byId("configurationWorkspace");
    workspace.classList.remove("is-refreshing");
    requestAnimationFrame(() => workspace.classList.add("is-refreshing"));
  }
}

function populateSelects() {
  for (let position = 1; position <= 4; position += 1) {
    const select = byId(`au${position}`);
    select.innerHTML = AU_VALUES.map(
      (value) => `<option value="${value}">${value || "No module"}</option>`,
    ).join("");
    select.addEventListener("change", () => {
      state.pro.aus[position - 1] = select.value;
      renderAll();
    });
  }
}

function getLocalizedConfigurationSummary() {
  const summary = getConfigurationSummary(state);
  if (currentLanguage !== "de") return summary;

  return summary
    .split("\n")
    .map((line) => {
      let localized = line
        .replace(/^Sequence:/, "Reihenfolge:")
        .replace(/^Check:/, "Prüfung:")
        .replace(/: Yes$/, ": Ja")
        .replace(/: No$/, ": Nein")
        .replace(/\bVALID\b/, "GÜLTIG")
        .replace(/\bWARNING\b/, "WARNUNG")
        .replace(/\bERROR\b/, "FEHLER")
        .replace(/\bEMPTY\b/, "LEER");
      const separator = localized.indexOf(" · ");
      if (separator >= 0) {
        const prefix = localized.slice(0, separator + 3);
        const message = localized.slice(separator + 3);
        localized = `${prefix}${translateValue(message, "de")}`;
      }
      return localized;
    })
    .join("\n");
}

