function initSearch() {
  const dialog = byId("searchDialog");
  const input = byId("searchInput");
  const results = byId("searchResults");
  const openButtons = all("[data-open-search]");

  const getSearchItems = () => [
    {
      title: "Configuration",
      text: "cobas pro pure modules DIP switch AU ISE NEO ISE PMC2 SW14",
      route: "configure",
    },
    {
      title: "Disconnect connectors",
      text: "P141 P7 P2003 P121 P133 P114 P41 P40 P32 alarm line",
      route: "connectors",
    },
    {
      title: "Additional assembly",
      text: "accessories cartons gripper needle calibration CD LAN cable",
      route: "assembly",
    },
    ...DOCUMENTS.map((document) => ({
      title: localizedDocumentValue(document, "title"),
      text: [
        document.title,
        document.titleDe,
        document.description,
        document.descriptionDe,
        document.system,
        document.category,
        document.categoryDe,
        document.type,
        ...document.folder.map(documentFolderLabel),
      ]
        .filter(Boolean)
        .join(" "),
      route: "documents",
      documentId: document.id,
    })),
    {
      title: "PCC Monsheim contact",
      text: "address email Wormser Strasse",
      route: "contact",
    },
  ];

  function updateResults() {
    const query = input.value.trim().toLowerCase();
    const searchItems = getSearchItems();
    const matches = searchItems.filter((item) => {
      const haystack = [
        item.title,
        item.text,
        translateValue(item.title, "de"),
        translateValue(item.text, "de"),
      ]
        .join(" ")
        .toLowerCase();
      return !query || haystack.includes(query);
    });
    results.innerHTML = matches.length
      ? matches
          .map(
            (item, index) => `
          <button type="button" data-search-route="${item.route}"${item.documentId ? ` data-search-document="${escapeHtml(item.documentId)}"` : ""} style="--item-index:${index}">
            <span><strong>${escapeHtml(item.title)}</strong><small>${escapeHtml(item.text)}</small></span>
            ${icon("arrow", 18)}
          </button>`,
          )
          .join("")
      : `<div class="search-empty">No matching instructions found.</div>`;
    translateSubtree(results);

    all("[data-search-route]", results).forEach((button) => {
      button.addEventListener("click", () => {
        dialog.close();
        setRoute(button.dataset.searchRoute);
        if (button.dataset.searchDocument) {
          const targetDocument = DOCUMENTS.find(
            (document) => document.id === button.dataset.searchDocument,
          );
          currentDocumentFolder = targetDocument
            ? [...targetDocument.folder]
            : [];
          byId("documentSearchInput").value = "";
          byId("documentSystemFilter").value = "";
          byId("documentCategoryFilter").value = "";
          renderDocuments();
          window.setTimeout(
            () =>
              byId(`document-${button.dataset.searchDocument}`)?.scrollIntoView({
                behavior: "smooth",
                block: "center",
              }),
            80,
          );
        }
      });
    });
  }

  function openSearch() {
    dialog.showModal();
    input.value = "";
    updateResults();
    window.setTimeout(() => input.focus(), 50);
  }

  openButtons.forEach((button) => button.addEventListener("click", openSearch));
  byId("closeSearch").addEventListener("click", () => dialog.close());
  input.addEventListener("input", updateResults);
  dialog.addEventListener("click", (event) => {
    if (event.target === dialog) dialog.close();
  });

  window.addEventListener("keydown", (event) => {
    const target = event.target;
    const typing =
      target instanceof HTMLInputElement ||
      target instanceof HTMLTextAreaElement ||
      target instanceof HTMLSelectElement;
    if ((event.ctrlKey || event.metaKey) && event.key.toLowerCase() === "k") {
      event.preventDefault();
      openSearch();
    } else if (!typing && event.key === "/") {
      event.preventDefault();
      openSearch();
    }
  });
}

